Implementing **Google Login** in a **Node.js** application involves several steps, including:

1. **Registering your application with Google**.
2. **Setting up the backend** to handle the OAuth flow.
3. **Handling the authentication response** and storing user data.
4. **Allowing users to log in** using the Google account.

---

## ✅ Step-by-Step: Implement Google Login in Node.js

---

### 📌 1. Register Your Application with Google

1. Go to the [Google Cloud Console](https://console.cloud.google.com/).
2. Create a new project or select an existing one.
3. Navigate to **APIs & Services > Credentials**.
4. Click **Create Credentials** > **OAuth client ID**.
5. Select **Web application**.
6. Enter the **Authorized JavaScript origins** and **Authorized redirect URIs** (e.g., `http://localhost:3000`).

- **OAuth Client ID** will be needed in the backend.
- **Client Secret** will also be needed.

---

### 📌 2. Install Required Packages

Install the necessary packages:

```bash
npm install express passport passport-google-oauth20
```

---

### 📌 3. Create the Server (app.js)

```js
const express = require('express');
const passport = require('passport');
const GoogleStrategy = require('passport-google-oauth20').Strategy;

const app = express();

// Set up Passport with Google Strategy
passport.use(
  new GoogleStrategy(
    {
      clientID: 'YOUR_GOOGLE_CLIENT_ID',
      clientSecret: 'YOUR_GOOGLE_CLIENT_SECRET',
      callbackURL: '/auth/google/callback'
    },
    (token, refreshToken, profile, done) => {
      // In a real app, you'd save the user to a DB
      return done(null, profile);
    }
  )
);

// Serialize and deserialize user
passport.serializeUser((user, done) => {
  done(null, user.id);
});

passport.deserializeUser((id, done) => {
  done(null, id);
});

// Initialize Passport
app.use(passport.initialize());

// Routes
app.get('/auth/google',
  passport.authenticate('google', {
    scope: ['profile', 'email']
  })
);

app.get('/auth/google/callback',
  passport.authenticate('google', {
    failureRedirect: '/login'
  }),
  (req, res) => {
    // Successful authentication, redirect to home
    res.redirect('/');
  }
);

// Simple route to show user data
app.get('/', (req, res) => {
  if (req.user) {
    res.send(`Logged in as: ${req.user.displayName}`);
  } else {
    res.send('Not logged in');
  }
});

// Start the server
const PORT = 3000;
app.listen(PORT, () => {
  console.log(`Server is running on http://localhost:${PORT}`);
});
```

---

### 📌 4. Run the Application

```bash
node app.js
```

Navigate to `http://localhost:3000/auth/google` to start the login flow.

---

### 📌 5. (Optional) Store User Data

In a real app, you would save the user data to a database. Here's an example using a simple in-memory store:

```js
let users = [];

passport.use(
  new GoogleStrategy(
    {
      clientID: 'YOUR_CLIENT_ID',
      clientSecret: 'YOUR_CLIENT_SECRET',
      callbackURL: '/auth/google/callback'
    },
    (token, refreshToken, profile, done) => {
      // Check if user exists
      const existingUser = users.find(user => user.id === profile.id);
      if (existingUser) {
        return done(null, existingUser);
      }

      // Create a new user
      const newUser = {
        id: profile.id,
        displayName: profile.displayName,
        email: profile.emails[0].value,
        avatar: profile.photos[0].value
      };
      users.push(newUser);
      return done(null, newUser);
    }
  )
);
