public function adopt(Adoptable $adoptable)
{
    $user = Auth::user();

    if ($user->currency < 10) {
        return back()->with('error', 'You don’t have enough currency to adopt this!');
    }

    $user->currency -= 10;
    $user->save();

    $adoptable->user_id = $user->id;
    $adoptable->save();

