Sure, here's an implementation in Go that finds the union, intersection, and symmetric difference of two unsorted integer arrays:
```go
package main

import (
    "fmt"
)

func main() {
    A := []int{1, 2, 3, 4, 5, 6, 7}
    B := []int{5, 6, 7, 8, 9, 10, 11}

    // Union
    union := make(map[int]bool)
    for _, a := range A {
        union[a] = true
    }
    for _, b := range B {
        union[b] = true
    }
    var U []int
    for k := range union {
        U = append(U, k)
    }
    fmt.Println("Union:", U)

    // Intersection
    intersection := make(map[int]bool)
    for _, a := range A {
        intersection[a] = true
    }
    var I []int
    for _, b := range B {
        if intersection[b] {
            I = append(I, b)
        }
    }
    fmt.Println("Intersection:", I)

    // Symmetric Difference
    symmetricDiff := make(map[int]bool)
    for _, a := range A {
        symmetricDiff[a] = true
    }
    for _, b := range B {
        if symmetricDiff[b] {
            delete(symmetricDiff, b)
        } else {
            symmetricDiff[b] = true
        }
    }
    var SD []int
    for k := range symmetricDiff {
        SD = append(SD, k)
    }
    fmt.Println("Symmetric Difference:", SD)
